async function run(params, api) {
  var repo = params.repo;
  var path = params.path || '';
  var ref = params.ref ? '?ref=' + encodeURIComponent(params.ref) : '';
  var url = 'https://api.github.com/repos/' + repo + '/contents/' + path + ref;
  api.log('Reading: ' + repo + '/' + path);
  var raw = await api.httpGet(url);
  var data = JSON.parse(raw);
  if (Array.isArray(data)) {
    var listing = data.map(function(item) {
      return { name: item.name, type: item.type, size: item.size, path: item.path };
    });
    return JSON.stringify({ type: 'directory', path: path || '/', items: listing }, null, 2);
  }
  if (data.encoding === 'base64' && data.content) {
    var decoded = '';
    var b64 = data.content.replace(/\n/g, '');
    for (var i = 0; i < b64.length; i += 1024) {
      decoded += atob(b64.slice(i, i + 1024));
    }
    if (decoded.length > 20000) decoded = decoded.slice(0, 20000) + '\n... [truncated]';
    return JSON.stringify({ type: 'file', path: data.path, size: data.size, content: decoded }, null, 2);
  }
  return JSON.stringify(data, null, 2);
}
